  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('9abe8925-3e4d-5a6b-8df3-5292cae5598a', 'math-6eme', 'قابلية القسمة على 2 و3 و5 و9 و10', 'معاييرُ قابلية القسمة: على 2 و5 و10 (رقم الآحاد)، وعلى 3 و9 (مجموع الأرقام)، والعلاقةُ بين القسمة على 9 و3', '# 🔍 قابليّةُ القسمة (على 2 و3 و5 و9 و10)

> 💡 «بنظرةٍ سريعةٍ إلى أرقام العدد تعرف هل يقبل القسمةَ دون أن تَقسِم.»

تُمكّنك **معاييرُ قابليّة القسمة** من معرفة هل يقبل عددٌ القسمةَ على آخر (الباقي 0) دون إجراء القسمة فعليًّا.

## ✌️ القسمةُ على 2 و5 و10 — ننظر إلى رقم الآحاد

- **على 2:** يقبل العددُ القسمةَ على 2 إذا كان رقمُ آحاده **زوجيًّا** (0، 2، 4، 6، 8)؛ ونقول إنّ العددَ **زوجيّ**.
- **على 5:** إذا كان رقمُ آحاده **0 أو 5**.
- **على 10:** إذا كان رقمُ آحاده **0**.
- _أمثلة:_ 84 يقبل القسمة على 2 (آحاده 4)؛ 95 يقبل القسمة على 5 (آحاده 5)؛ 730 يقبل القسمة على 10 و5 و2 (آحاده 0).

## 🔢 القسمةُ على 3 و9 — نجمع الأرقام

- **على 3:** يقبل العددُ القسمةَ على 3 إذا كان **مجموعُ أرقامه** يقبل القسمة على 3.
- **على 9:** إذا كان **مجموعُ أرقامه** يقبل القسمة على 9.
- _مثال:_ 471 ⟸ مجموعُ أرقامه 4 + 7 + 1 = 12، و12 يقبل القسمة على 3 (لا على 9)؛ إذن 471 يقبل القسمة على 3 لا على 9.
- _مثال:_ 522 ⟸ مجموعُ أرقامه 5 + 2 + 2 = 9، فهو يقبل القسمة على 9 (وعلى 3 كذلك).

> 🗡️ كلُّ عددٍ يقبل القسمة على 9 يقبلها على 3 (لأنّ 9 مضاعفٌ للعدد 3)، والعكسُ ليس صحيحًا دائمًا (471 شاهدٌ على ذلك).

> ⚠️ الفخّ الشائع: تطبيقُ قاعدة «جمع الأرقام» على 2 أو 5 (وهي خاصّةٌ بـ3 و9 فقط)، أو الاكتفاءُ بالنظر إلى الآحاد للحكم على القسمة على 3.

## 🧭 لماذا تنفعنا؟

تُسهّل قابليّةُ القسمة إيجادَ قواسم العدد بسرعة، واختزالَ الكسور لاحقًا.

> 🏆 صرتَ تحكم على قابليّة القسمة بنظرةٍ ذكيّة. أنت الآن جاهزٌ لعالَم الكسور.', '# 📜 ملخّص: قابليّة القسمة

- **على 2:** رقمُ الآحاد زوجيّ (0، 2، 4، 6، 8) → العددُ زوجيّ.
- **على 5:** رقمُ الآحاد 0 أو 5.
- **على 10:** رقمُ الآحاد 0.
- **على 3:** مجموعُ الأرقام يقبل القسمة على 3.
- **على 9:** مجموعُ الأرقام يقبل القسمة على 9.
- كلُّ ما يقبل القسمة على 9 يقبلها على 3 (والعكسُ ليس دائمًا صحيحًا).', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('63d67f33-ac18-5bd8-829f-33cf72696737', 'math-6eme', 'الأعداد الكسرية: المعنى والقراءة والكتابة', 'البسط والمقام، الكسرُ كجزءٍ من الوحدة ومن كمية، قراءةُ الكسور، الكسرُ على نصف المستقيم المدرّج، الكسرُ حاصلَ قسمة، ومقارنتُه بالوحدة', '# 🍕 الأعداد الكسرية — أن تأخذ جزءًا من الكلّ

> 💡 «الكسرُ يقول لك: قَسِّمِ الوحدةَ إلى أجزاءٍ متساوية، ثمّ خُذ بعضَها.»

## 🧩 ما هو الكسر؟

الكسرُ يتكوّن من عددين: **البسط** (فوق الخطّ) و**المقام** (تحته).

$$\frac{\text{البسط}}{\text{المقام}}$$

- **المقام** يدلّ على عدد الأجزاء المتساوية التي قُسّمت إليها الوحدة.
- **البسط** يدلّ على عدد الأجزاء التي أخذناها.
- _مثال:_ في $\frac{3}{4}$ (ثلاثةُ أرباع): قُسّمت الوحدةُ إلى 4 أجزاء متساوية وأُخذت 3 منها.

## 🔢 قراءةُ الكسور

- $\frac{1}{2}$ نصف، $\frac{1}{3}$ ثلث، $\frac{1}{4}$ ربع، $\frac{1}{5}$ خمس، $\frac{1}{10}$ عشر…
- $\frac{3}{4}$ ثلاثةُ أرباع، $\frac{2}{3}$ ثلثان، $\frac{5}{8}$ خمسةُ أثمان.

## 📏 الكسرُ على نصف المستقيم المدرّج

نقسم القطعةَ بين 0 و 1 إلى أجزاءٍ بعدد المقام، فيقع الكسرُ عند البسط.

- $\frac{3}{4}$ يقع عند الجزء الثالث بين 0 و 1.

## ⚖️ مقارنةُ الكسر بالوحدة

- إذا كان **البسط < المقام** فالكسرُ **أصغرُ من 1** (مثل $\frac{2}{3}$).
- إذا كان **البسط = المقام** فالكسرُ **يساوي 1** (مثل $\frac{4}{4} = 1$).
- إذا كان **البسط > المقام** فالكسرُ **أكبرُ من 1** (مثل $\frac{5}{4} > 1$).

## ➗ الكسرُ حاصلُ قسمة

الكسرُ $\frac{a}{b}$ يساوي حاصلَ قسمة البسط على المقام: $\frac{a}{b} = a \div b$.

- _مثال:_ $\frac{3}{4} = 3 \div 4 = 0,75$.

## 🎯 كسرٌ من كمية

لحساب كسرٍ من كمية: نقسم الكميةَ على المقام ثمّ نضرب في البسط.

- _مثال:_ $\frac{3}{4}$ من 20 = (20 ÷ 4) × 3 = 5 × 3 = 15.

> ⚠️ الفخّ الشائع: الخلطُ بين البسط والمقام عند القراءة أو الحساب؛ تذكّر أنّ **المقام تحت** وهو يُحدّد عددَ الأجزاء.

> 🏆 صرتَ تفهم الكسرَ وتقرؤه وتحسب جزءًا من كمية. التالي: الكتاباتُ الكسرية المتساوية واختزالُ الكسور.', '# 📜 ملخّص: الأعداد الكسرية (المعنى والقراءة)

- **الكسر** = البسط / المقام: المقامُ عددُ الأجزاء المتساوية للوحدة، والبسطُ عددُ الأجزاء المأخوذة.
- **القراءة:** 1/2 نصف، 1/4 ربع، 3/4 ثلاثةُ أرباع…
- **مقارنةٌ بالوحدة:** بسط < مقام ⟹ أصغرُ من 1؛ بسط = مقام ⟹ يساوي 1؛ بسط > مقام ⟹ أكبرُ من 1.
- **الكسر حاصلُ قسمة:** a/b = a ÷ b (مثال: 3/4 = 0,75).
- **كسرٌ من كمية:** نقسم على المقام ثمّ نضرب في البسط (3/4 من 20 = 15).', 8)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('08c50bc6-1fde-5b0d-8e63-aafe2839d20e', 'math-6eme', 'الكتابات الكسرية المتساوية واختزال الكسور', 'الكسورُ المتساوية (ضربُ/قسمةُ البسط والمقام في العدد نفسه)، إيجادُ كسرٍ مساوٍ بمقامٍ معيّن، اختزالُ الكسر بقاسمٍ مشترك، والكسرُ غيرُ القابل للاختزال', '# 🟰 الكتابات الكسرية المتساوية واختزال الكسور

> 💡 «الكسرُ نفسُه يمكن أن يلبس عدّةَ أثواب: 1/2 = 2/4 = 3/6 = 5/10.»

## ⚖️ كسرانِ متساويان

نحصل على كسرٍ يساوي كسرًا معطًى إذا ضربنا (أو قسمنا) **البسطَ والمقامَ معًا** في **العدد نفسِه** غيرِ المعدوم:

$$\frac{a}{b} = \frac{a \times k}{b \times k} = \frac{a \div k}{b \div k}$$

- _مثال:_ $\frac{1}{2} = \frac{1\times2}{2\times2} = \frac{2}{4} = \frac{3}{6} = \frac{5}{10}$.

## 🎯 إيجادُ كسرٍ مساوٍ بمقامٍ معيّن

نسأل: «بِكم نضرب المقامَ لنبلغ المقامَ المطلوب؟» ثمّ نضرب البسطَ في العدد نفسِه.

- _مثال:_ $\frac{2}{3} = \frac{?}{12}$ ⟸ بما أنّ 3 × 4 = 12، نضرب البسطَ أيضًا في 4: $\frac{2}{3} = \frac{8}{12}$.

## ✂️ اختزالُ الكسر

اختزالُ الكسر يعني كتابتَه بأبسط صورة: نقسم البسطَ والمقامَ على **قاسمٍ مشترك** (نستعين بمعايير قابلية القسمة من الدرس السابق).

- _مثال:_ $\frac{6}{8} = \frac{6\div2}{8\div2} = \frac{3}{4}$.
- _مثال:_ $\frac{10}{15} = \frac{10\div5}{15\div5} = \frac{2}{3}$.

الكسرُ **غيرُ القابل للاختزال** هو الذي ليس لبسطه ومقامه قاسمٌ مشترك أكبرُ من 1 (مثل $\frac{3}{4}$).

> 🗡️ للاختزال دفعةً واحدة: اقسم على **القاسم المشترك الأكبر** للبسط والمقام؛ مثلًا $\frac{12}{16}$ نقسمه على 4 فنحصل مباشرةً على $\frac{3}{4}$.

> ⚠️ الفخّ الشائع: قسمةُ البسط وحدَه أو المقام وحدَه (يُغيّر قيمةَ الكسر)؛ يجب قسمةُ الاثنين على العدد نفسِه.

> 🏆 صرتَ تكتب كسورًا متساوية وتختزلها. التالي: مقارنةُ الكسور وترتيبُها.', '# 📜 ملخّص: الكتابات الكسرية المتساوية والاختزال

- **كسرانِ متساويان:** نضرب أو نقسم البسطَ والمقامَ معًا في العدد نفسِه غيرِ المعدوم: a/b = (a×k)/(b×k).
- **مثال:** 1/2 = 2/4 = 3/6 = 5/10.
- **كسرٌ مساوٍ بمقامٍ معيّن:** نضرب المقامَ والبسطَ في العامل المناسب (2/3 = 8/12، لأنّ 3 × 4 = 12).
- **الاختزال:** نقسم البسطَ والمقامَ على قاسمٍ مشترك (6/8 = 3/4)؛ وبالقاسم المشترك الأكبر نختزل دفعةً واحدة.
- **كسرٌ غيرُ قابلٍ للاختزال:** لا قاسمَ مشتركًا للبسط والمقام أكبرُ من 1 (مثل 3/4).', 9)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('2c4227cf-b46f-53cf-92b6-d5f0c086c5ce', 'math-6eme', 'مقارنة الأعداد الكسرية وترتيبها', 'مقارنةُ كسرين لهما المقامُ نفسُه أو البسطُ نفسُه، المقارنةُ بالوحدة، توحيدُ المقامات لمقارنة مقاماتٍ مختلفة، وترتيبُ الكسور تصاعديًّا وتنازليًّا', '# ⚖️ مقارنةُ الأعداد الكسرية وترتيبُها

> 💡 «لمقارنة كسرين، اجعل لهما المقامَ نفسَه، ثمّ انظر إلى البُسُط.»

## 1️⃣ كسرانِ لهما المقامُ نفسُه

الأكبرُ هو صاحبُ **البسط الأكبر**.

- _مثال:_ $\frac{3}{7} < \frac{5}{7}$ لأنّ 3 < 5.

## 2️⃣ كسرانِ لهما البسطُ نفسُه

الأكبرُ هو صاحبُ **المقام الأصغر** (الأجزاء أكبر).

- _مثال:_ $\frac{2}{3} > \frac{2}{5}$ لأنّ الأثلاثَ أكبرُ من الأخماس.

## 3️⃣ مقارنةٌ بالوحدة

- بسط < مقام ⟹ الكسرُ < 1، وبسط > مقام ⟹ الكسرُ > 1.
- يُفيد ذلك للمقارنة السريعة: كلُّ كسرٍ أصغرَ من 1 أصغرُ من أيّ كسرٍ أكبرَ من 1.

## 4️⃣ مقاماتٌ مختلفة: نوحّد المقامات

نكتب الكسرين بكسرين متساويين لهما **المقامُ نفسُه** (مضاعفٌ مشترك للمقامين)، ثمّ نقارن البُسُط.

- _مثال:_ مقارنة $\frac{2}{3}$ و $\frac{3}{4}$ ⟸ نوحّد على 12: $\frac{2}{3} = \frac{8}{12}$ و $\frac{3}{4} = \frac{9}{12}$؛ وبما أنّ 8 < 9 فإنّ $\frac{2}{3} < \frac{3}{4}$.

## 🔢 الترتيب

بعد التوحيد (أو عند تساوي المقام) نرتّب الكسورَ **تصاعديًّا** أو **تنازليًّا** حسب البُسُط.

- _مثال:_ ترتيب $\frac{1}{4}, \frac{1}{2}, \frac{3}{4}$ تصاعديًّا (نوحّد على 4): $\frac{1}{4} < \frac{2}{4} < \frac{3}{4}$.

> ⚠️ الفخّ الشائع: مقارنةُ البُسُط مباشرةً دون توحيد المقامات؛ فالكسرُ 3/4 ليس أصغرَ من 5/8 رغم أنّ 3 < 5 (لأنّ 3/4 = 6/8 > 5/8).

> 🏆 صرتَ تقارن الكسورَ وترتّبها. التالي: جمعُ الكسور وطرحُها.', '# 📜 ملخّص: مقارنة الكسور وترتيبها

- **مقامٌ مشترك:** الأكبرُ بسطًا هو الأكبر (3/7 < 5/7).
- **بسطٌ مشترك:** الأصغرُ مقامًا هو الأكبر (2/3 > 2/5).
- **مقارنةٌ بالوحدة:** بسط < مقام ⟹ < 1؛ بسط > مقام ⟹ > 1.
- **مقاماتٌ مختلفة:** نوحّد المقامات (مضاعفٌ مشترك) ثمّ نقارن البُسُط (2/3 = 8/12 < 9/12 = 3/4).
- **الترتيب:** بعد التوحيد، تصاعديًّا أو تنازليًّا حسب البُسُط.
- ⚠️ لا نقارن البُسُط مباشرةً دون توحيد المقامات.', 10)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('df941fe9-b3e3-5598-b20a-e05e33b39f6a', 'math-6eme', 'جمع وطرح الأعداد الكسرية', 'جمعُ وطرحُ كسرين لهما المقامُ نفسُه، التوحيدُ قبل الجمع/الطرح عند اختلاف المقامات، العمليّاتُ بين كسرٍ وعددٍ صحيح، واختزالُ النتيجة', '# ➕➖ جمعُ الأعداد الكسرية وطرحُها

> 💡 «لجمع كسرين أو طرحهما، يجب أوّلًا أن يكون لهما المقامُ نفسُه.»

## 1️⃣ مقامٌ مشترك

إذا كان للكسرين **المقامُ نفسُه**، نجمع (أو نطرح) **البُسُط** ونُبقي المقامَ كما هو.

- _مثال:_ $\frac{2}{7} + \frac{3}{7} = \frac{2+3}{7} = \frac{5}{7}$.
- _مثال:_ $\frac{5}{8} - \frac{2}{8} = \frac{5-2}{8} = \frac{3}{8}$.

## 2️⃣ مقاماتٌ مختلفة: نوحّد أوّلًا

نكتب الكسرين بمقامٍ مشترك (مضاعفٌ مشترك للمقامين)، ثمّ نجمع أو نطرح البُسُط.

- _مثال:_ $\frac{1}{2} + \frac{1}{3}$ ⟸ نوحّد على 6: $\frac{3}{6} + \frac{2}{6} = \frac{5}{6}$.
- _مثال:_ $\frac{3}{4} - \frac{1}{2}$ ⟸ نوحّد على 4: $\frac{3}{4} - \frac{2}{4} = \frac{1}{4}$.

## 3️⃣ كسرٌ مع عددٍ صحيح

نكتب العددَ الصحيح في صورة كسرٍ بالمقام نفسِه، ثمّ نجمع أو نطرح.

- _مثال:_ $1 + \frac{1}{4} = \frac{4}{4} + \frac{1}{4} = \frac{5}{4}$.
- _مثال:_ $2 - \frac{1}{3} = \frac{6}{3} - \frac{1}{3} = \frac{5}{3}$.

## ✂️ اختزالُ النتيجة

إذا أمكن اختزالُ الكسر الناتج، نكتبه بأبسط صورة.

- _مثال:_ $\frac{2}{6} + \frac{1}{6} = \frac{3}{6} = \frac{1}{2}$.

> ⚠️ الفخّ الشائع: جمعُ المقامات أيضًا (مثل كتابة 1/2 + 1/3 = 2/5)؛ المقامُ لا يُجمع، بل نوحّده ونجمع البُسُط فقط.

> 🏆 أتممتَ رحلةَ الكسور: المعنى، التساوي والاختزال، المقارنة، والجمع والطرح. أنت بطلٌ في عالَم الأعداد الكسرية!', '# 📜 ملخّص: جمع وطرح الأعداد الكسرية

- **مقامٌ مشترك:** نجمع/نطرح البُسُط ونُبقي المقام (2/7 + 3/7 = 5/7).
- **مقاماتٌ مختلفة:** نوحّد على مضاعفٍ مشترك، ثمّ نجمع/نطرح البُسُط (1/2 + 1/3 = 3/6 + 2/6 = 5/6).
- **كسرٌ مع عددٍ صحيح:** نكتب الصحيحَ كسرًا بالمقام نفسِه (1 + 1/4 = 4/4 + 1/4 = 5/4).
- **اختزالُ النتيجة** إن أمكن (2/6 + 1/6 = 3/6 = 1/2).
- ⚠️ لا نجمع المقامات؛ المقامُ يبقى (بعد التوحيد) ونجمع البُسُط فقط.', 11)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('b74ec658-cff2-5483-8314-0189bed02dc9', 'math-6eme', 'الأعداد الكسرية العشرية', 'الكسورُ ذات المقام 10 و100 و1000، الانتقالُ بين الكسر العشريّ والعدد العشريّ، اختزالُ الكسور العشرية، وتحويلُ كسرٍ إلى كسرٍ عشريّ', '# 🔟 الأعداد الكسرية العشرية

> 💡 «الكسرُ العشريّ جسرٌ بين الكسور والأعداد العشرية: 3/10 = 0,3.»

## 🎯 ما هو الكسر العشري؟

الكسرُ العشريّ هو كسرٌ مقامُه **10 أو 100 أو 1000…** (قوّةٌ للعدد 10).

- $\frac{3}{10}, \frac{7}{100}, \frac{125}{1000}$ كسورٌ عشرية.

## 🔄 من الكسر العشري إلى العدد العشري

عددُ أصفار المقام = عددُ الأرقام بعد الفاصلة:

- $\frac{3}{10} = 0,3$ ؛ $\frac{7}{100} = 0,07$ ؛ $\frac{25}{100} = 0,25$ ؛ $\frac{125}{1000} = 0,125$.

## 🔁 من العدد العشري إلى الكسر العشري

- $0,4 = \frac{4}{10}$ ؛ $0,09 = \frac{9}{100}$ ؛ $1,25 = \frac{125}{100}$.

## ✂️ اختزالُ الكسر العشري

كثيرٌ من الكسور العشرية تُختزل إلى كسورٍ أبسط:

- $\frac{5}{10} = \frac{1}{2}$ ؛ $\frac{25}{100} = \frac{1}{4}$ ؛ $\frac{8}{10} = \frac{4}{5}$.

## ➡️ تحويلُ كسرٍ إلى كسرٍ عشريّ

إذا أمكن جعلُ المقام 10 أو 100… بالضرب، نحصل على القيمة العشرية بسهولة:

- $\frac{1}{2} = \frac{5}{10} = 0,5$ ؛ $\frac{3}{4} = \frac{75}{100} = 0,75$ ؛ $\frac{7}{20} = \frac{35}{100} = 0,35$.

> ⚠️ الفخّ الشائع: الخلطُ بين عدد أصفار المقام وعدد الأرقام بعد الفاصلة (7/100 = 0,07 وليس 0,7).

> 🏆 صرتَ تنتقل بين الكسور والأعداد العشرية بسهولة. التالي: ضربُ عددٍ كسريّ في عددٍ صحيح.', '# 📜 ملخّص: الأعداد الكسرية العشرية

- **كسرٌ عشريّ:** مقامُه 10 أو 100 أو 1000…
- **إلى عدد عشري:** عددُ أصفار المقام = عددُ الأرقام بعد الفاصلة (3/10 = 0,3، 7/100 = 0,07).
- **إلى كسر عشري:** 0,4 = 4/10، 1,25 = 125/100.
- **الاختزال:** 5/10 = 1/2، 25/100 = 1/4.
- **تحويلُ كسرٍ:** اجعل المقام 10/100 بالضرب (3/4 = 75/100 = 0,75).', 12)
