INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('6ddcff47-ff2d-5137-bd3a-d629480fb06b', 'math-6eme', 'التناسب: السرعة والمسافة والزمن', 'معدّلُ السرعة (المسافة ÷ الزمن)، حسابُ المسافة (السرعة × الزمن) والزمن (المسافة ÷ السرعة)، والانتباهُ إلى الوحدات', '# 🚗 التناسب: السرعة والمسافة والزمن

> 💡 «السرعةُ تربط المسافةَ بالزمن: كم تقطع في كلّ ساعة.»

## 📐 العلاقاتُ الثلاث

معدّلُ **السرعة** هو المسافةُ المقطوعة في وحدة زمن (مثلًا في ساعة):

$$\text{السرعة} = \frac{\text{المسافة}}{\text{الزمن}}$$

ومنها نستنتج:

$$\text{المسافة} = \text{السرعة} \times \text{الزمن} \qquad \text{الزمن} = \frac{\text{المسافة}}{\text{السرعة}}$$

## 🧮 أمثلة

- قطعت سيّارةٌ 120 km في ساعتين ⟸ السرعة = 120 ÷ 2 = **60 km/h**.
- سار دراجٌ بسرعة 20 km/h لمدّة 3 ساعات ⟸ المسافة = 20 × 3 = **60 km**.
- قطع قطارٌ 150 km بسرعة 50 km/h ⟸ الزمن = 150 ÷ 50 = **3 ساعات**.

## ⏱️ انتبه إلى الوحدات

- السرعةُ بـ km/h تعني «كيلومترًا في الساعة»؛ فالزمنُ يجب أن يكون بالساعات.
- نصفُ ساعة = 0,5 ساعة، وثلثُ ساعة (20 دقيقة) = $\frac{1}{3}$ ساعة.
- _مثال:_ سيّارةٌ بسرعة 90 km/h تقطع في نصف ساعة: 90 × 0,5 = 45 km.

> ⚠️ الفخّ الشائع: عكسُ العلاقة (قسمةُ الزمن على المسافة)، أو خلطُ الدقائق بالساعات.

> 🏆 أتممتَ توظيفَ التناسب في السرعة والمسافة والزمن — وبهذا تكتمل الأنشطةُ العددية والتناسب في برنامج السنة السادسة!', '# 📜 ملخّص: السرعة والمسافة والزمن

- **السرعة = المسافة ÷ الزمن** (120 km في 2 ساعة ⟹ 60 km/h).
- **المسافة = السرعة × الزمن** (20 km/h × 3 ساعات = 60 km).
- **الزمن = المسافة ÷ السرعة** (150 km ÷ 50 km/h = 3 ساعات).
- **الوحدات:** السرعةُ بـ km/h ⟹ الزمنُ بالساعات (نصفُ ساعة = 0,5؛ 20 دقيقة = 1/3 ساعة).', 15)
